(window.webpackJsonp=window.webpackJsonp||[]).push([[68],{695:function(n,r){n.exports="\x3c!-- \r\ntitle: 02-Linux命令\r\nsort: \r\n--\x3e \r\n# Linux命令\r\n\r\n> 命令有多种类型\r\n\r\n## 帮助\r\n\r\n- type———显示命令类型\r\n\r\n- which——显示可执行程序的位置\r\n\r\n- help———得到内建函数的帮助文档\r\n\r\n  > `--help`显示用法信息\r\n\r\n- man———显示程序手册\r\n\r\n- whatis——简洁的命令说明\r\n\r\n- alias———创建别名\r\n\r\n## 重定向\r\n\r\n> `> clean.txt`：清空文件\r\n>\r\n> `&> output.txt`：标准错误重定向：\r\n>\r\n> `2> /dev/null`：错误信息放到垃圾桶\r\n\r\n- cat———连接文件\r\n\r\n  > `cat > out.txt`\r\n  >\r\n  > `Some Text <Ctrl+D>`\r\n\r\n-  | ————管道\r\n\r\n  > `ll xx | less`\r\n\r\n- sort\r\n\r\n  > `ls /bin /usr/bin | sort | less`\r\n\r\n- wc———行数 单词数 字节数\r\n\r\n  > -c\tbyte\r\n  >\r\n  > -m\tcharacter\r\n  >\r\n  > -l\tlines\r\n  >\r\n  > -w\twords\r\n  >\r\n  > -L\tMAX_LEN\r\n\r\n- grep———打印匹配行\r\n\r\n  > -i\tignore\r\n  >\r\n  > -v\t打印不匹配的行\r\n\r\n- head、tail—打印开头、结尾\r\n\r\n  > -n\t行数\r\n  >\r\n  > tail -f 实时预览\r\n\r\n- tee———中转\r\n\r\n  > 输出到文件并沿着管道向下\r\n  >\r\n  > `ll /usr/bin | tee ls.txt | grep zip`"}}]);